&lt;p style=&quot;&quot;&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Nokrek.&lt;/span&gt;&lt;/u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Nokrek Biosphere Reserve &lt;/span&gt;&lt;span style=&quot;&quot;&gt;is a Biosphere Reserve, a part of the Garo Hills in Meghalaya.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;representative parts&lt;/span&gt;&amp;nbsp;of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;natural and cultural landscapes&lt;/span&gt;&amp;nbsp;extending over&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;large areas of terrestrial or coastal/ marine ecosystems&lt;/span&gt;&amp;nbsp;or a c&lt;span style=&quot;font-weight: 700;&quot;&gt;ombination of both&lt;/span&gt;&amp;nbsp;designated by the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;United Nations Educational, Scientific and Cultural Organisation&amp;nbsp;&lt;/span&gt;(UNESCO)&amp;nbsp; is called a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Biosphere Reserve&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

