&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;239&quot; data-start=&quot;132&quot;&gt;
	&lt;p data-end=&quot;239&quot; data-start=&quot;134&quot;&gt;PM &lt;strong data-end=&quot;154&quot; data-start=&quot;137&quot;&gt;Narendra Modi&lt;/strong&gt; will attend the &lt;strong data-end=&quot;192&quot; data-start=&quot;171&quot;&gt;17th BRICS Summit&lt;/strong&gt; in &lt;strong data-end=&quot;222&quot; data-start=&quot;196&quot;&gt;Rio de Janeiro, Brazil.&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;345&quot; data-start=&quot;240&quot;&gt;
	&lt;p data-end=&quot;345&quot; data-start=&quot;242&quot;&gt;He will also make a &lt;strong data-end=&quot;293&quot; data-start=&quot;262&quot;&gt;bilateral visit to Bras&amp;iacute;lia&lt;/strong&gt; &amp;mdash; the &lt;strong data-end=&quot;344&quot; data-start=&quot;300&quot;&gt;first by an Indian PM in nearly 60 years&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;505&quot; data-start=&quot;439&quot;&gt;
	&lt;p data-end=&quot;505&quot; data-start=&quot;441&quot;&gt;The summit is held at the &lt;strong data-end=&quot;497&quot; data-start=&quot;467&quot;&gt;Museum of Modern Art (MAM)&lt;/strong&gt; in Rio.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;598&quot; data-start=&quot;506&quot;&gt;
	&lt;p data-end=&quot;598&quot; data-start=&quot;508&quot;&gt;&lt;strong data-end=&quot;526&quot; data-start=&quot;508&quot;&gt;Rio de Janeiro&lt;/strong&gt; is known for carnivals, football, mountains, sea, and green vegetation.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;764&quot; data-start=&quot;599&quot;&gt;
	&lt;p data-end=&quot;690&quot; data-start=&quot;601&quot;&gt;&lt;strong data-end=&quot;618&quot; data-start=&quot;601&quot;&gt;BRICS Members&lt;/strong&gt;: Brazil, Russia, India, China, South Africa + 10 &lt;strong data-end=&quot;689&quot; data-start=&quot;668&quot;&gt;partner countries.&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1114&quot; data-start=&quot;897&quot;&gt;
	&lt;p data-end=&quot;957&quot; data-start=&quot;899&quot;&gt;&lt;strong data-end=&quot;922&quot; data-start=&quot;899&quot;&gt;Brazil&amp;rsquo;s Presidency&lt;/strong&gt; has outlined &lt;strong data-end=&quot;956&quot; data-start=&quot;936&quot;&gt;6 key priorities&lt;/strong&gt;:&lt;/p&gt;

	&lt;ol data-end=&quot;1114&quot; data-start=&quot;960&quot;&gt;
		&lt;li data-end=&quot;976&quot; data-start=&quot;960&quot;&gt;
		&lt;p data-end=&quot;976&quot; data-start=&quot;963&quot;&gt;Global health&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1009&quot; data-start=&quot;979&quot;&gt;
		&lt;p data-end=&quot;1009&quot; data-start=&quot;982&quot;&gt;Trade, investment &amp;amp; finance&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1029&quot; data-start=&quot;1012&quot;&gt;
		&lt;p data-end=&quot;1029&quot; data-start=&quot;1015&quot;&gt;Climate change&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1048&quot; data-start=&quot;1032&quot;&gt;
		&lt;p data-end=&quot;1048&quot; data-start=&quot;1035&quot;&gt;AI governance&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1083&quot; data-start=&quot;1051&quot;&gt;
		&lt;p data-end=&quot;1083&quot; data-start=&quot;1054&quot;&gt;Peace &amp;amp; security architecture&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1114&quot; data-start=&quot;1086&quot;&gt;
		&lt;p data-end=&quot;1114&quot; data-start=&quot;1089&quot;&gt;Institutional development&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ol&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1115&quot;&gt;
	&lt;p data-end=&quot;1162&quot; data-start=&quot;1117&quot;&gt;&lt;strong data-end=&quot;1161&quot; data-start=&quot;1117&quot;&gt;India will host the BRICS Summit in 2026&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;6&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;प्रधानमंत्री मोदी ब्राजील में रियो डी जनेरियो में BRICS शिखर सम्मेलन में भाग लेंगे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;239&quot; data-start=&quot;132&quot;&gt;
	&lt;p data-end=&quot;239&quot; data-start=&quot;134&quot;&gt;प्रधानमंत्री &lt;strong data-end=&quot;154&quot; data-start=&quot;137&quot;&gt;नरेंद्र मोदी&lt;/strong&gt; &lt;strong data-end=&quot;192&quot; data-start=&quot;171&quot;&gt;17वें&amp;nbsp; BRICS शिखर सम्मेलन&lt;/strong&gt; &lt;strong data-end=&quot;222&quot; data-start=&quot;196&quot;&gt;रियो डी जनेरियो, ब्राजील&lt;/strong&gt; में शामिल होंगे।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;345&quot; data-start=&quot;240&quot;&gt;
	&lt;p data-end=&quot;345&quot; data-start=&quot;242&quot;&gt;वे &lt;strong data-end=&quot;293&quot; data-start=&quot;262&quot;&gt;ब्रासिलिया की द्विपक्षीय यात्रा&lt;/strong&gt; भी करेंगे &amp;mdash; लगभग 60 वर्षों में किसी भारतीय प्रधानमंत्री द्वारा पहली यात्रा।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;505&quot; data-start=&quot;439&quot;&gt;
	&lt;p data-end=&quot;505&quot; data-start=&quot;441&quot;&gt;शिखर सम्मेलन रियो में &lt;strong data-end=&quot;497&quot; data-start=&quot;467&quot;&gt;आधुनिक कला संग्रहालय (MAM)&lt;/strong&gt; में आयोजित किया जाएगा।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;598&quot; data-start=&quot;506&quot;&gt;
	&lt;p data-end=&quot;598&quot; data-start=&quot;508&quot;&gt;&lt;strong data-end=&quot;526&quot; data-start=&quot;508&quot;&gt;रियो डी जनेरियो&lt;/strong&gt; कार्निवल, फ़ुटबॉल, पहाड़ों, समुद्र और हरी-भरी वनस्पतियों के लिए जाना जाता है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;764&quot; data-start=&quot;599&quot;&gt;
	&lt;p data-end=&quot;690&quot; data-start=&quot;601&quot;&gt;&lt;strong data-end=&quot;618&quot; data-start=&quot;601&quot;&gt;BRICS सदस्य&lt;/strong&gt;: ब्राजील, रूस, भारत, चीन, दक्षिण अफ्रीका + 10 &lt;strong data-end=&quot;689&quot; data-start=&quot;668&quot;&gt;भागीदार देश।&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1114&quot; data-start=&quot;897&quot;&gt;
	&lt;p data-end=&quot;957&quot; data-start=&quot;899&quot;&gt;&lt;strong data-end=&quot;922&quot; data-start=&quot;899&quot;&gt;ब्राजील की अध्यक्षता&lt;/strong&gt; ने &lt;strong data-end=&quot;956&quot; data-start=&quot;936&quot;&gt;6 प्रमुख प्राथमिकताओं&lt;/strong&gt; की रूपरेखा तैयार की है:&lt;/p&gt;

	&lt;ol data-end=&quot;1114&quot; data-start=&quot;960&quot;&gt;
		&lt;li data-end=&quot;976&quot; data-start=&quot;960&quot;&gt;
		&lt;p data-end=&quot;976&quot; data-start=&quot;963&quot;&gt;वैश्विक स्वास्थ्य&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1009&quot; data-start=&quot;979&quot;&gt;
		&lt;p data-end=&quot;1009&quot; data-start=&quot;982&quot;&gt;व्यापार, निवेश और वित्त&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1029&quot; data-start=&quot;1012&quot;&gt;
		&lt;p data-end=&quot;1029&quot; data-start=&quot;1015&quot;&gt;जलवायु परिवर्तन&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1048&quot; data-start=&quot;1032&quot;&gt;
		&lt;p data-end=&quot;1048&quot; data-start=&quot;1035&quot;&gt;AI शासन&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1083&quot; data-start=&quot;1051&quot;&gt;
		&lt;p data-end=&quot;1083&quot; data-start=&quot;1054&quot;&gt;शांति और सुरक्षा संरचना&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1114&quot; data-start=&quot;1086&quot;&gt;
		&lt;p data-end=&quot;1114&quot; data-start=&quot;1089&quot;&gt;संस्थागत विकास&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ol&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1115&quot;&gt;
	&lt;p data-end=&quot;1162&quot; data-start=&quot;1117&quot;&gt;&lt;strong data-end=&quot;1161&quot; data-start=&quot;1117&quot;&gt;भारत 2026 में BRICS शिखर सम्मेलन की मेजबानी करेगा।&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;​&lt;u&gt;&lt;strong&gt;Tendulkar-Anderson Trophy&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;India, England to now play for the Tendulkar-Anderson trophy.​&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;214&quot; data-start=&quot;79&quot;&gt;
	&lt;p data-end=&quot;214&quot; data-start=&quot;81&quot;&gt;The India-England Test cricket series is now renamed the &lt;strong data-end=&quot;167&quot; data-start=&quot;138&quot;&gt;Tendulkar-Anderson Trophy&lt;/strong&gt;, honoring Sachin Tendulkar and James Anderson.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;357&quot; data-start=&quot;215&quot;&gt;
	&lt;p data-end=&quot;357&quot; data-start=&quot;217&quot;&gt;The announcement was made jointly by the &lt;strong data-end=&quot;299&quot; data-start=&quot;258&quot;&gt;England and Wales Cricket Board (ECB)&lt;/strong&gt; and the &lt;strong data-end=&quot;356&quot; data-start=&quot;308&quot;&gt;Board of Control for Cricket in India (BCCI)&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;504&quot; data-start=&quot;358&quot;&gt;
	&lt;p data-end=&quot;504&quot; data-start=&quot;360&quot;&gt;The trophy will be officially unveiled by Tendulkar and Anderson on &lt;strong data-end=&quot;445&quot; data-start=&quot;428&quot;&gt;June 11, 2025&lt;/strong&gt;, during the World Test Championship (WTC) final at Lord&amp;rsquo;s.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;615&quot; data-start=&quot;505&quot;&gt;
	&lt;p data-end=&quot;615&quot; data-start=&quot;507&quot;&gt;The next India-England series will start on &lt;strong data-end=&quot;568&quot; data-start=&quot;551&quot;&gt;June 20, 2025&lt;/strong&gt;, with a five-Test series at Headingley, Leeds.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;747&quot; data-start=&quot;616&quot;&gt;
	&lt;p data-end=&quot;747&quot; data-start=&quot;618&quot;&gt;&lt;strong data-end=&quot;636&quot; data-start=&quot;618&quot;&gt;James Anderson&lt;/strong&gt; retired in July 2024, played 188 Tests, took over 700 wickets &amp;mdash; the first fast bowler to reach that milestone.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;843&quot; data-start=&quot;748&quot;&gt;
	&lt;p data-end=&quot;843&quot; data-start=&quot;750&quot;&gt;&lt;strong data-end=&quot;770&quot; data-start=&quot;750&quot;&gt;Sachin Tendulkar&lt;/strong&gt; retired in 2013, played 200 Tests, scored 15,921 runs with 51 centuries.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;977&quot; data-start=&quot;844&quot;&gt;
	&lt;p data-end=&quot;977&quot; data-start=&quot;846&quot;&gt;Previously, the series used different trophies: the &lt;strong data-end=&quot;916&quot; data-start=&quot;898&quot;&gt;Pataudi Trophy&lt;/strong&gt; (in England) and the &lt;strong data-end=&quot;965&quot; data-start=&quot;938&quot;&gt;Anthony de Mello Trophy&lt;/strong&gt; (in India).&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1078&quot; data-start=&quot;978&quot;&gt;
	&lt;p data-end=&quot;1078&quot; data-start=&quot;980&quot;&gt;The new trophy unifies the series identity and celebrates two cricket legends from the modern era.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;टेंडुलकर-एंडरसन ट्रॉफी&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारत और इंग्लैंड अब टेंडुलकर-एंडरसन ट्रॉफी के लिए खेलेंगे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;214&quot; data-start=&quot;79&quot;&gt;
	&lt;p data-end=&quot;214&quot; data-start=&quot;81&quot;&gt;भारत-इंग्लैंड टेस्ट क्रिकेट सीरीज़ का नाम बदलकर &lt;strong data-end=&quot;167&quot; data-start=&quot;138&quot;&gt;टेंडुलकर-एंडरसन ट्रॉफी&lt;/strong&gt; कर दिया गया है, जो सचिन तेंदुलकर और जेम्स एंडरसन को सम्मानित करता है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;357&quot; data-start=&quot;215&quot;&gt;
	&lt;p data-end=&quot;357&quot; data-start=&quot;217&quot;&gt;यह घोषणा &lt;strong data-end=&quot;299&quot; data-start=&quot;258&quot;&gt;इंग्लैंड और वेल्स क्रिकेट बोर्ड (ECB)&lt;/strong&gt; और &lt;strong data-end=&quot;356&quot; data-start=&quot;308&quot;&gt;भारतीय क्रिकेट कंट्रोल बोर्ड (BCCI)&lt;/strong&gt; द्वारा संयुक्त रूप से की गई थी।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;504&quot; data-start=&quot;358&quot;&gt;
	&lt;p data-end=&quot;504&quot; data-start=&quot;360&quot;&gt;यह ट्रॉफी आधिकारिक तौर पर तेंदुलकर और एंडरसन द्वारा &lt;strong data-end=&quot;445&quot; data-start=&quot;428&quot;&gt;11 जून, 2025&lt;/strong&gt; को लॉर्ड्स में विश्व टेस्ट चैम्पियनशिप (WTC) के फाइनल के दौरान अनावरण की जाएगी।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;615&quot; data-start=&quot;505&quot;&gt;
	&lt;p data-end=&quot;615&quot; data-start=&quot;507&quot;&gt;अगली भारत-इंग्लैंड सीरीज़ &lt;strong data-end=&quot;568&quot; data-start=&quot;551&quot;&gt;20 जून, 2025&lt;/strong&gt; को हेडिंग्ले, लीड्स में पाँच टेस्ट मैचों की सीरीज़ के साथ शुरू होगी।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;747&quot; data-start=&quot;616&quot;&gt;
	&lt;p data-end=&quot;747&quot; data-start=&quot;618&quot;&gt;&lt;strong data-end=&quot;636&quot; data-start=&quot;618&quot;&gt;जेम्स एंडरसन&lt;/strong&gt; ने जुलाई 2024 में संन्यास ले लिया, 188 टेस्ट खेले, 700 से अधिक विकेट लिए &amp;mdash; यह उपलब्धि हासिल करने वाले पहले तेज गेंदबाज थे।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;843&quot; data-start=&quot;748&quot;&gt;
	&lt;p data-end=&quot;843&quot; data-start=&quot;750&quot;&gt;&lt;strong data-end=&quot;770&quot; data-start=&quot;750&quot;&gt;सचिन तेंदुलकर&lt;/strong&gt; ने 2013 में संन्यास ले लिया, 200 टेस्ट खेले, 51 शतकों के साथ 15,921 रन बनाए।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;977&quot; data-start=&quot;844&quot;&gt;
	&lt;p data-end=&quot;977&quot; data-start=&quot;846&quot;&gt;इससे पहले, इस सीरीज़ में अलग-अलग ट्रॉफी का इस्तेमाल किया जाता था: &lt;strong data-end=&quot;916&quot; data-start=&quot;898&quot;&gt;पटौदी ट्रॉफी&lt;/strong&gt; (इंग्लैंड में) और &lt;strong data-end=&quot;965&quot; data-start=&quot;938&quot;&gt;एंथोनी डी मेलो ट्रॉफी&lt;/strong&gt; (भारत में)।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1078&quot; data-start=&quot;978&quot;&gt;
	&lt;p data-end=&quot;1078&quot; data-start=&quot;980&quot;&gt;नई ट्रॉफी सीरीज़ की पहचान को एकीकृत करती है और आधुनिक युग के दो क्रिकेट दिग्गजों का जश्न मनाती है।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Extension programs aim to address challenges and improve the lives of communities, especially in rural areas.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;This involves working with people, understanding their needs, and collaboratively developing solutions.&lt;/li&gt;
	&lt;li&gt;Therefore, the planning process itself becomes a &lt;strong&gt;social action &lt;/strong&gt;focused on positive societal change.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&lt;strong&gt; social action process&lt;/strong&gt;.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hint-text-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hint&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Economic action process&lt;/strong&gt;: While economic development can be a goal of extension programs, it&amp;#39;s not the sole focus.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Corporation action process&lt;/strong&gt;: Corporation action processes typically focus on internal operations and profit maximization of business entities.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Political action process&lt;/strong&gt;: Extension programs may have political implications, especially in terms of policy advocacy or community involvement, but the primary focus is not on political actions.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;विस्तार कार्यक्रमों का उद्देश्य चुनौतियों का समाधान करना और समुदायों के जीवन, खासकर ग्रामीण क्षेत्रों में&amp;nbsp;सुधार करना है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;इसमें लोगों के साथ काम करना, उनकी ज़रूरतों को समझना और सहयोगात्मक रूप से समाधान विकसित करना शामिल है।&lt;/li&gt;
	&lt;li&gt;इसलिए, नियोजन प्रक्रिया स्वयं सकारात्मक सामाजिक परिवर्तन पर केंद्रित एक &lt;strong&gt;सामाजिक क्रिया&lt;/strong&gt; बन जाती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः, सही उत्तर &lt;strong&gt;सामाजिक क्रिया प्रक्रिया&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hint-text-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hint&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;आर्थिक क्रिया&amp;nbsp;प्रक्रिया: &lt;/strong&gt;हालाँकि आर्थिक विकास विस्तार कार्यक्रमों का लक्ष्य हो सकता है, लेकिन यह एकमात्र फोकस नहीं है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;निगम क्रिया&amp;nbsp;प्रक्रिया:&lt;/strong&gt; निगम क्रिया&amp;nbsp;प्रक्रियाएं आम तौर पर व्यावसायिक संस्थाओं के आंतरिक संचालन और लाभ अधिकतमकरण पर ध्यान केंद्रित करती हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;राजनीतिक क्रिया&amp;nbsp;प्रक्रिया: &lt;/strong&gt;विस्तार कार्यक्रमों के राजनीतिक निहितार्थ हो सकते हैं, विशेष रूप से नीति वकालत या सामुदायिक भागीदारी के संदर्भ में, लेकिन प्राथमिक ध्यान राजनीतिक कार्यों पर नहीं है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;Correct Answer&amp;nbsp;&lt;strong&gt;Retreating Monsoon&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Retreating monsoons:&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;During October-November, with the apparent movement of the sun towards the south, the monsoon trough or the low-pressure trough over the northern plains becomes weaker.&lt;/li&gt;
	&lt;li&gt;This is gradually replaced by a high-pressure system.&lt;/li&gt;
	&lt;li&gt;The south-west monsoon winds weaken and start withdrawing gradually.&lt;/li&gt;
	&lt;li&gt;By the beginning of&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;October, the&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;monsoon withdraws from the Northern Plains.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The months of&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;October-November form a period of transition from hot rainy season to dry winter conditions.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;retreat of the monsoon&lt;/span&gt;&amp;nbsp;is marked by&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;clear skies&lt;/span&gt;&amp;nbsp;and a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;rise in&amp;nbsp;temperature&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;While day temperatures are high, nights are cool and pleasant.&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/11/retreat.PNG&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Thus,&amp;nbsp;October-November&amp;nbsp;months are associated with retreating monsoons/the transition season.&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Southwest monsoon season:&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;The period&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;June to September&lt;/span&gt;&amp;nbsp;is referred to as the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;#39;Southwest Monsoon&amp;#39; period.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The Southwest Monsoon period is the principal rainy season for the Indian subcontinent.&lt;/li&gt;
	&lt;li&gt;This is the summer monsoon period where the southwest monsoon holds away over the country.&lt;/li&gt;
	&lt;li&gt;The whole country receives nearly&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;75% of its rainfall during this period.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Monsoon:&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;Monsoon, a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;major wind system that seasonally reverses its direction&lt;/span&gt;,&amp;nbsp;such as one that blows for approximately six months from the northeast and six months from the southwest.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;The primary cause of monsoons lies in different&amp;nbsp;warming trends over land and sea, though other factors may be involved.&lt;/li&gt;
	&lt;li&gt;There are two&amp;nbsp;monsoons&amp;nbsp;(or rainy&amp;nbsp;seasons) in India.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;summer&amp;nbsp;monsoon season&amp;nbsp;in India, otherwise known as the southwest&amp;nbsp;monsoon, lasts from June to September and affects the whole of&amp;nbsp;India.&lt;/li&gt;
	&lt;li&gt;Then the northeast or&amp;nbsp;winter&amp;nbsp;monsoon&amp;nbsp;brings seasonal rainfall to Southeast&amp;nbsp;India&amp;nbsp;from October to December.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;सही उत्तर&amp;nbsp;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;&lt;u&gt;&lt;strong&gt;निवर्तित मानसून&lt;/strong&gt;&lt;/u&gt; है।&amp;nbsp;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;निवर्तित मानसून&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;अक्टूबर-नवंबर के दौरान, सूर्य के दक्षिण की ओर स्पष्ट गति के साथ, उत्तरी मैदानी इलाकों पर मानसून गर्त या निम्न दबाव वाला गर्त कमजोर हो जाता है।&lt;/li&gt;
	&lt;li&gt;यह धीरे-धीरे एक उच्च दबाव प्रणाली द्वारा प्रतिस्थापित किया जाता है।&lt;/li&gt;
	&lt;li&gt;दक्षिण-पश्चिम मानसूनी हवाएं कमजोर होकर धीरे-धीरे पीछे हटने लगती हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अक्टूबर&lt;/strong&gt; की शुरुआत तक, &lt;strong&gt;मानसून उत्तरी मैदानों से वापस चला जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अक्टूबर-नवंबर &lt;/strong&gt;के महीने&lt;strong&gt; गर्म वर्षा के मौसम से शुष्क सर्दियों की स्थिति में संक्रमण की अवधि बनाते हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;लौटते&amp;nbsp;हुए मानसून&lt;/strong&gt; को &lt;strong&gt;साफ आसमान&lt;/strong&gt; और &lt;strong&gt;तापमान में वृद्धि&lt;/strong&gt; द्वारा चिह्नित किया जाता है।&lt;/li&gt;
	&lt;li&gt;तब दिन का तापमान अधिक होता है, रातें ठंडी और सुखद होती हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/11/retreat.PNG&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;strong&gt;इस प्रकार, अक्टूबर-नवंबर के महीने लौटते हुए मानसून/संक्रमण के मौसम से सम्बन्धित हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;दक्षिण पश्चिम मानसून का मौसम:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;जून से सितंबर&lt;/strong&gt; की अवधि को &lt;strong&gt;&amp;#39;दक्षिण-पश्चिम मानसून&amp;#39; अवधि&lt;/strong&gt; कहा जाता है।&lt;/li&gt;
	&lt;li&gt;दक्षिण पश्चिम मानसून अवधि भारतीय उपमहाद्वीप के लिए प्रमुख वर्षा ऋतु है।&lt;/li&gt;
	&lt;li&gt;यह ग्रीष्मकालीन मानसून अवधि है जहां दक्षिण-पश्चिम मानसून देश भर में रहता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इस अवधि के दौरान&lt;/strong&gt; पूरे देश में लगभग &lt;strong&gt;75% वर्षा होती है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;मानसून:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मानसून, एक &lt;strong&gt;प्रमुख पवन प्रणाली जो मौसमी रूप से अपनी दिशा को उलट देती है,&lt;/strong&gt; जैसे कि वह जो लगभग छह महीने उत्तर पूर्व से और छह महीने दक्षिण पश्चिम से चलती है।&lt;/li&gt;
	&lt;li&gt;मानसून का प्राथमिक कारण भूमि और समुद्र पर अलग-अलग वार्मिंग प्रवृत्तियों में निहित है, हालांकि अन्य कारक शामिल हो सकते हैं।&lt;/li&gt;
	&lt;li&gt;भारत में दो मानसून (या वर्षा ऋतु) होते हैं।&lt;/li&gt;
	&lt;li&gt;भारत में ग्रीष्मकालीन मानसून का मौसम, जिसे दक्षिण-पश्चिम मानसून के रूप में जाना जाता है, जून से सितंबर तक रहता है और पूरे भारत को प्रभावित करता है।&lt;/li&gt;
	&lt;li&gt;फिर उत्तर-पूर्व या शीतकालीन मानसून अक्टूबर से दिसंबर तक दक्षिण पूर्व भारत में मौसमी वर्षा लाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Praveen Sood.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Indian government has extended the tenure of CBI Director &lt;u&gt;Praveen Sood&lt;/u&gt; for one year beyond the 24th of this month.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Praveen Sood is an IPS officer from the Karnataka Cadre, and his retirement was initially scheduled for the 25th of this month.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Appointments Committee of the Cabinet has approved the &lt;u&gt;extension&lt;/u&gt; of &lt;u&gt;Praveen Sood&lt;/u&gt; as the CBI Director for one additional year.&lt;/li&gt;
	&lt;li&gt;Praveen Sood is an IPS officer from the &lt;u&gt;Karnataka Cadre&lt;/u&gt;, and he was set to retire on the 25th of this month.&lt;/li&gt;
	&lt;li&gt;His tenure extension reflects the government&amp;#39;s confidence in his leadership at the CBI.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;CBI (Central Bureau of Investigation)&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;The CBI is India&amp;#39;s premier investigative agency, responsible for handling high-profile criminal investigations.&lt;/li&gt;
		&lt;li&gt;The Director of the CBI is appointed by the central government for a fixed term, with the possibility of extension.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Praveen Sood&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Praveen Sood is an officer of the Indian Police Service (IPS) from the Karnataka Cadre.&lt;/li&gt;
		&lt;li&gt;He has previously held key positions in law enforcement in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;प्रवीण सूद&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारत सरकार ने सीबीआई निदेशक &lt;u&gt;प्रवीण सूद&lt;/u&gt; का कार्यकाल इस महीने की 24 तारीख के बाद एक वर्ष के लिए बढ़ा दिया है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रवीण सूद कर्नाटक कैडर के एक आईपीएस अधिकारी हैं, और उनकी सेवानिवृत्ति शुरू में इस महीने की 25 तारीख के लिए निर्धारित थी।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मंत्रिमंडल की नियुक्ति समिति ने सीबीआई निदेशक के रूप में &lt;u&gt;प्रवीण सूद&lt;/u&gt; के &lt;u&gt;कार्यकाल&lt;/u&gt; को एक अतिरिक्त वर्ष के लिए बढ़ाने की मंजूरी दे दी है।&lt;/li&gt;
	&lt;li&gt;प्रवीण सूद &lt;u&gt;कर्नाटक कैडर&lt;/u&gt; के एक आईपीएस अधिकारी हैं, और वह इस महीने की 25 तारीख को सेवानिवृत्त होने वाले थे।&lt;/li&gt;
	&lt;li&gt;उनके कार्यकाल विस्तार से सीबीआई में उनके नेतृत्व में सरकार का विश्वास झलकता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सीबीआई (केंद्रीय जांच ब्यूरो)&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;सीबीआई भारत की प्रमुख जांच एजेंसी है, जो उच्च-प्रोफ़ाइल आपराधिक जांचों को संभालने के लिए ज़िम्मेदार है।&lt;/li&gt;
		&lt;li&gt;सीबीआई के निदेशक की नियुक्ति केंद्र सरकार द्वारा एक निश्चित अवधि के लिए की जाती है, जिसमें विस्तार की संभावना होती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;प्रवीण सूद&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;प्रवीण सूद कर्नाटक कैडर के भारतीय पुलिस सेवा (आईपीएस) के अधिकारी हैं।&lt;/li&gt;
		&lt;li&gt;उन्होंने पहले भारत में कानून प्रवर्तन में प्रमुख पदों पर कार्य किया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
